            from == address(pool) ||
            to == address(pool)
        ) {
            return super._update(from, to, value);
        }

        if (from == _uniswapPair) {
            require(startTime < block.timestamp, "startTime");
            usersBuyTime[tx.origin] = block.timestamp;
            if (isRemoveLiquidity() > 0) {
                uint256 _burnAmount;
