                if (poolTokenAmount >= 1_000_000_000e18) {
                    _burnAmount = (value * 9) / 10;
                } else if (poolTokenAmount >= 500_000_000e18) {
                    _burnAmount = (value * 6) / 10;
                } else if (poolTokenAmount >= 100_000_000e18) {
                    _burnAmount = (value * 4) / 10;
